const input = $input.first().json;
const body = input.body || input;
const { projectId, requirements, constraints } = body;

const reqList = Array.isArray(requirements) ? requirements : [];
const constraintList = Array.isArray(constraints) ? constraints : [];

const needs = {
  frontend: false,
  backend: false,
  database: false,
  auth: false,
  realtime: false,
  fileStorage: false,
  search: false,
  ml: false,
  ci: false,
  containerization: false
};

const keywords = {
  frontend: ['ui', 'frontend', 'web', 'dashboard', 'portal', 'spa', 'pwa', 'responsive', 'mobile-web'],
  backend: ['api', 'backend', 'server', 'rest', 'graphql', 'microservice', 'service'],
  database: ['database', 'db', 'storage', 'persistence', 'data', 'sql', 'nosql', 'cache'],
  auth: ['auth', 'login', 'sso', 'oauth', 'jwt', 'rbac', 'permissions', 'security'],
  realtime: ['realtime', 'websocket', 'live', 'streaming', 'push', 'notification'],
  fileStorage: ['file', 'upload', 'blob', 'media', 'image', 'document', 'asset'],
  search: ['search', 'fulltext', 'filter', 'index', 'elasticsearch', 'query'],
  ml: ['ml', 'ai', 'machine-learning', 'model', 'inference', 'training', 'llm'],
  ci: ['ci', 'cd', 'pipeline', 'deploy', 'test', 'automation', 'build'],
  containerization: ['docker', 'container', 'kubernetes', 'k8s', 'orchestration']
};

const allText = reqList.join(' ').toLowerCase();
Object.entries(keywords).forEach(([category, words]) => {
  if (words.some(w => allText.includes(w))) {
    needs[category] = true;
  }
});

if (!Object.values(needs).some(v => v)) {
  needs.backend = true;
  needs.database = true;
}

return [{
  json: {
    projectId,
    requirements: reqList,
    constraints: constraintList,
    identifiedNeeds: needs,
    activeNeeds: Object.entries(needs).filter(([,v]) => v).map(([k]) => k)
  }
}];

const data = $json;
const { projectId, constraints, identifiedNeeds, activeNeeds } = data;

const constraintSet = new Set((constraints || []).map(c => c.toLowerCase()));

const catalog = {
  frontend: [
    { name: 'React 19', category: 'frontend', rationale: 'Mature ecosystem, large community, Server Components support', fit: 9 },
    { name: 'Next.js 15', category: 'frontend', rationale: 'Full-stack React framework with SSR/SSG and API routes', fit: 8 },
    { name: 'Tailwind CSS v4', category: 'styling', rationale: 'Utility-first CSS, rapid prototyping, consistent design system', fit: 9 }
  ],
  backend: [
    { name: 'Node.js + Express 5', category: 'backend', rationale: 'Fast development, TypeScript native, large package ecosystem', fit: 8 },
    { name: 'Fastify', category: 'backend', rationale: 'High-performance Node.js framework with schema validation', fit: 7 }
  ],
  database: [
    { name: 'PostgreSQL 17', category: 'database', rationale: 'ACID-compliant, JSON support, excellent for structured data', fit: 9 },
    { name: 'Drizzle ORM', category: 'orm', rationale: 'Type-safe, lightweight, SQL-first ORM for TypeScript', fit: 8 }
  ],
  auth: [
    { name: 'Lucia Auth', category: 'auth', rationale: 'Lightweight, database-agnostic session management', fit: 7 },
    { name: 'Auth.js (NextAuth)', category: 'auth', rationale: 'OAuth providers, session management, JWT support', fit: 8 }
  ],
  realtime: [
    { name: 'Socket.io', category: 'realtime', rationale: 'WebSocket abstraction with fallbacks and room support', fit: 8 }
  ],
  fileStorage: [
    { name: 'S3-compatible (MinIO)', category: 'storage', rationale: 'Self-hosted object storage, S3 API compatible', fit: 8 }
  ],
  search: [
    { name: 'MeiliSearch', category: 'search', rationale: 'Fast, typo-tolerant search engine with simple setup', fit: 7 }
  ],
  ml: [
    { name: 'Ollama + Local LLMs', category: 'ml', rationale: 'Self-hosted inference, no API costs, data privacy', fit: 7 },
    { name: 'LangChain.js', category: 'ml-framework', rationale: 'LLM orchestration with chains, agents, and memory', fit: 7 }
  ],
  ci: [
    { name: 'GitHub Actions', category: 'ci', rationale: 'Native GitHub integration, YAML-based, free for public repos', fit: 9 }
  ],
  containerization: [
    { name: 'Docker + Docker Compose', category: 'container', rationale: 'Standard containerization, local dev and production parity', fit: 9 }
  ]
};

const resolvedStack = [];
const rationale = [];

activeNeeds.forEach(need => {
  const options = catalog[need] || [];
  const filtered = options.filter(opt => {
    if (constraintSet.has('no-cloud') && (opt.name.includes('AWS') || opt.name.includes('Cloud'))) return false;
    if (constraintSet.has('self-hosted') && opt.name.includes('Vercel')) return false;
    return true;
  });

  const best = filtered.sort((a, b) => b.fit - a.fit)[0];
  if (best) {
    resolvedStack.push(best);
    rationale.push({
      need: need,
      chosen: best.name,
      reason: best.rationale,
      fitScore: best.fit,
      alternativesConsidered: filtered.length - 1
    });
  }
});

return [{
  json: {
    projectId,
    resolvedStack,
    rationale,
    summary: {
      totalNeeds: activeNeeds.length,
      resolved: resolvedStack.length,
      unresolved: activeNeeds.length - resolvedStack.length,
      avgFitScore: resolvedStack.length > 0
        ? Math.round((resolvedStack.reduce((s, t) => s + t.fit, 0) / resolvedStack.length) * 10) / 10
        : 0
    },
    completedAt: new Date().toISOString()
  }
}];
